 1	import React, { FC } from 'react';
 2	
 3	import {
 4	  ActionList,
 5	  ActionListItem,
 6	  Button,
 7	  ButtonVariant,
 8	  Modal,
 9	  ModalVariant,
10	} from '@patternfly/react-core';
11	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
12	
13	import '@styles/modal-action.scss';
14	
15	export type ConfirmModalProps = {
16	  btnText: JSX.Element | string;
17	  closeModal?: () => void;
18	  executeFn: () => void;
19	  message: JSX.Element | string;
20	  title: string;
21	};
22	
23	const ConfirmModal: FC<ConfirmModalProps> = ({
24	  btnText,
25	  closeModal,
26	  executeFn,
27	  message,
28	  title,
29	}) => {
30	  const { t } = useNetworkingTranslation();
31	
32	  return (
33	    <Modal
34	      className="ocs-modal networking-modal"
35	      footer={
36	        <ActionList className="tabmodal-footer">
37	          <ActionListItem>
38	            <Button onClick={executeFn} variant={ButtonVariant.primary}>
39	              {btnText || t('Confirm')}
40	            </Button>
41	          </ActionListItem>
42	          <ActionListItem>
43	            <Button onClick={closeModal} variant="link">
44	              {t('Cancel')}
45	            </Button>
46	          </ActionListItem>
47	        </ActionList>
48	      }
49	      id="confirm-modal"
50	      isOpen
51	      onClose={closeModal}
52	      position={'top'}
53	      title={title}
54	      titleIconVariant="warning"
55	      variant={ModalVariant.small}
56	    >
57	      {message}
58	    </Modal>
59	  );
60	};
61	
62	export default ConfirmModal;

